interface RateLimiterConfig {
  tokensPerSecond: number;      // refill rate
  maxBurstSize: number;         // burst capacity
  windowDurationMs?: number;    // for sliding window tracking (optional)
}

interface UserBucket {
  tokens: number;
  lastRefillTime: number;
}

export class RateLimiter {
  private config: RateLimiterConfig;
  private userBuckets: Map<string, UserBucket> = new Map();

  constructor(config: RateLimiterConfig) {
    this.config = config;
  }

  allow(userId: string): boolean {
    const now = Date.now();
    let bucket = this.userBuckets.get(userId);

    if (!bucket) {
      bucket = {
        tokens: this.config.maxBurstSize,
        lastRefillTime: now
      };
      this.userBuckets.set(userId, bucket);
    }

    // Refill tokens based on time elapsed
    const timeDelta = (now - bucket.lastRefillTime) / 1000; // convert to seconds
    const tokensToAdd = timeDelta * this.config.tokensPerSecond;
    bucket.tokens = Math.min(
      this.config.maxBurstSize,
      bucket.tokens + tokensToAdd
    );
    bucket.lastRefillTime = now;

    // Check if we have at least 1 token to consume
    if (bucket.tokens >= 1) {
      bucket.tokens -= 1;
      return true;
    }
    return false;
  }
}
```

